SELECT id, activity_id AS activityId, activity_name AS name, start_time AS startTime, end_time AS endTime, AS status, create_time AS createTime, update_time AS updateTime, create_by AS createBy, update_by AS updateBy, deleted FROM colonel_activity WHERE deleted = 0
AND = #{status}
ORDER BY start_time DESC NULLS LAST, create_time DESC NULLS LAST LIMIT #{limit} OFFSET #{offset}

SELECT id, activity_id AS activityId, activity_name AS name, start_time AS startTime, end_time AS endTime, AS status, create_time AS createTime, update_time AS updateTime, create_by AS createBy, update_by AS updateBy, deleted FROM colonel_activity WHERE deleted = 0
AND activity_name ILIKE CONCAT('%', #{activityName}, '%')
ORDER BY start_time DESC NULLS LAST, create_time DESC NULLS LAST LIMIT #{limit} OFFSET #{offset}
